{"path": "/tmp/sv-5370c08880bf428eaea758528513abfe/Components/Catalog/CatalogFilters.razor", "file_text": "<aside class="catalog-filters">
    <h2>Filters</h2>

    <fieldset>
        <legend>Category</legend>
        @if (Categories.Count == 0)
        {
            <p class="filter-hint">Loading…</p>
        }
        else
        {
            @foreach (var category in Categories)
            {
                <label class="checkbox-label">
                    <input type="checkbox"
                           checked="@IsSelected(category)"
                           @onchange="() => ToggleCategory(category)" />
                    @category
                </label>
            }
        }
    </fieldset>

    <fieldset>
        <legend>Price Range</legend>
        <div class="price-inputs">
            <label>
                Min
                <input type="number" min="0" step="0.01"
                       value="@MinPrice"
                       @onchange="e => MinPrice = ParseDecimal(e.Value)" />
            </label>
            <label>
                Max
                <input type="number" min="0" step="0.01"
                       value="@MaxPrice"
                       @onchange="e => MaxPrice = ParseDecimal(e.Value)" />
            </label>
        </div>
    </fieldset>

    <label class="checkbox-label">
        <input type="checkbox" @bind="InStockOnly" />
        In Stock Only
    </label>

    <div class="filter-actions">
        <button class="btn btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    private HashSet<string> SelectedCategories { get; set; } = [];
    private decimal? MinPrice { get; set; }
    private decimal? MaxPrice { get; set; }
    private bool InStockOnly { get; set; }

    private bool IsSelected(string category) => SelectedCategories.Contains(category);

    private void ToggleCategory(string category)
    {
        if (!SelectedCategories.Remove(category))
        {
            SelectedCategories.Add(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: SelectedCategories.Count > 0 ? SelectedCategories.ToList() : null,
            MinPrice: MinPrice,
            MaxPrice: MaxPrice,
            InStockOnly: InStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        SelectedCategories.Clear();
        MinPrice = null;
        MaxPrice = null;
        InStockOnly = false;
        await OnApplyFilters.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

