.catalog-filters {
    padding: 1.5rem;
    background: #f9fafb;
    border-right: 1px solid #e0e0e0;
    height: 100%;
}

.catalog-filters h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
    color: #333;
}

fieldset {
    border: none;
    padding: 0;
    margin: 0 0 1.25rem;
}

legend {
    font-weight: 600;
    font-size: 0.9rem;
    color: #555;
    margin-bottom: 0.5rem;
    display: block;
}

.checkbox-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.25rem 0;
    cursor: pointer;
    font-size: 0.9rem;
}

.price-inputs {
    display: flex;
    gap: 0.75rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    font-size: 0.85rem;
    color: #555;
    flex: 1;
}

.price-inputs input {
    padding: 0.4rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    width: 100%;
    box-sizing: border-box;
}

.filter-hint {
    color: #999;
    font-size: 0.85rem;
    margin: 0;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1.5rem;
}

.btn {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.2s;
}

.btn-apply {
    background: #3182ce;
    color: #fff;
}

.btn-apply:hover {
    background: #2b6cb0;
}

.btn-clear {
    background: #e2e8f0;
    color: #4a5568;
}

.btn-clear:hover {
    background: #cbd5e0;
}

