@page "/catalog"
@using sv_5370c08880bf428eaea758528513abfe.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout">
    <CatalogFilters Categories="categories" OnApplyFilters="HandleApplyFilters" />

    <main class="catalog-main">
        @if (error is not null)
        {
            <div class="alert alert-error">
                <p>Something went wrong: @error</p>
                <button class="btn btn-retry" @onclick="LoadProducts">Try Again</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="loading-state">
                <p>Loading products…</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            Page="currentPage"
                            PageSize="PageSize"
                            TotalCount="totalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="products"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="currentPage"
                               TotalPages="totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int totalCount;
    private int totalPages;
    private bool isLoading = true;
    private string? error;

    protected override async Task OnInitializedAsync()
    {
        var categoriesTask = LoadCategories();
        var productsTask = LoadProducts();
        await Task.WhenAll(categoriesTask, productsTask);
    }

    private async Task LoadCategories()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = [];
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        error = null;

        try
        {
            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
            products = result.Items;
            totalCount = result.TotalCount;
            totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            error = ex.Message;
            products = [];
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

.catalog-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
}

.catalog-layout > :first-child {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
}

.catalog-main {
    flex: 1;
    padding: 1.5rem;
    min-width: 0;
}

.loading-state {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 4rem 1rem;
    color: #718096;
    font-size: 1.1rem;
}

.alert-error {
    background: #fff5f5;
    border: 1px solid #feb2b2;
    border-radius: 8px;
    padding: 1.5rem;
    text-align: center;
    color: #c53030;
}

.btn-retry {
    margin-top: 0.75rem;
    padding: 0.5rem 1rem;
    background: #e53e3e;
    color: #fff;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

.btn-retry:hover {
    background: #c53030;
}

